import { useState } from 'react';
import ChatBox from './components/ChatBox';
import Cart from './components/Cart';
import './App.css';

const STEPS = ['Chat', 'Ingredients', 'Review', 'Payment', 'Delivered'];
const SCREEN_TO_STEP = { chat: 0, ingredients: 1, review: 2, payment: 3, success: 4 };

function ProgressBar({ screen }) {
  const current = SCREEN_TO_STEP[screen] ?? 0;
  return (
    <div className="progress-bar">
      {STEPS.map((label, i) => (
        <div key={i} className={`progress-step ${i <= current ? 'progress-active' : ''}`}>
          <div className="progress-dot">{i < current ? '✓' : i + 1}</div>
          <div className="progress-label">{label}</div>
          {i < STEPS.length - 1 && (
            <div className={`progress-line ${i < current ? 'progress-line-active' : ''}`} />
          )}
        </div>
      ))}
    </div>
  );
}

function App() {
  const [screen, setScreen] = useState('chat');
  const [cart, setCart] = useState([]);
  const [orderSummary, setOrderSummary] = useState(null);

  const handleCartReady = (items) => {
    setCart(items);
    setScreen('review');
  };

  const handleRemove = (index) => {
    const updated = cart.filter((_, i) => i !== index);
    setCart(updated);
  };

  const handleOrderComplete = (summary) => {
    setOrderSummary(summary);
    setScreen('success');
  };

  const handleRestart = () => {
    setOrderSummary(null);
    setCart([]);
    setScreen('chat');
  };

  const total = cart.reduce((s, i) => s + parseFloat(i.price), 0).toFixed(2);

  return (
    <div className="app">
      <div className="header">
        <div className="brand">🛒 GroceryMind</div>
      </div>

      <ProgressBar screen={screen} />

      {screen === 'chat' && (
        <ChatBox
          onCartReady={handleCartReady}
          onOrderComplete={handleOrderComplete}
          onScreenChange={setScreen}
        />
      )}

      {screen === 'review' && (
        <Cart
          cart={cart}
          onRemove={handleRemove}
          onCheckout={() => setScreen('payment')}
          onBack={() => setScreen('chat')}
          isReview={true}
        />
      )}

      {screen === 'payment' && (
        <div className="payment-form">
          <h2>Payment</h2>
          <div className="order-summary">
            <span>Total to pay</span>
            <strong>£{total}</strong>
          </div>
          <div className="field">
            <label>Full name</label>
            <input id="pName" placeholder="Jane Smith" />
          </div>
          <div className="field">
            <label>Delivery address</label>
            <input id="pAddr" placeholder="123 Baker St, Manchester" />
          </div>
          <div className="field">
            <label>Card number</label>
            <input id="pCard" placeholder="4242 4242 4242 4242" maxLength={19} />
          </div>
          <div className="row2">
            <div className="field">
              <label>Expiry</label>
              <input placeholder="MM/YY" maxLength={5} />
            </div>
            <div className="field">
              <label>CVV</label>
              <input placeholder="123" maxLength={3} />
            </div>
          </div>
          <button className="pay-btn" onClick={() => {
            const name = document.getElementById('pName').value;
            const addr = document.getElementById('pAddr').value;
            const card = document.getElementById('pCard').value;
            if (!name || !addr || !card) {
              alert('Please fill in name, address and card number.');
              return;
            }
            handleOrderComplete({ address: addr, itemCount: cart.length, total });
          }}>
            Place order
          </button>
          <button className="back-btn" onClick={() => setScreen('review')}>
            ← Back to review
          </button>
          <p className="note">This is a demo. No real payment is processed.</p>
        </div>
      )}

      {screen === 'success' && orderSummary && (
        <div className="success">
          <div className="success-icon">🎉</div>
          <h2>Order confirmed!</h2>
          <div className="delivery-card">
            <div className="delivery-row">
              <span>📦</span>
              <div>
                <div className="delivery-label">Status</div>
                <div className="delivery-value">Order received & being packed</div>
              </div>
            </div>
            <div className="delivery-row">
              <span>🚚</span>
              <div>
                <div className="delivery-label">Estimated delivery</div>
                <div className="delivery-value">30–45 minutes to your door</div>
              </div>
            </div>
            <div className="delivery-row">
              <span>📍</span>
              <div>
                <div className="delivery-label">Delivering to</div>
                <div className="delivery-value">{orderSummary.address}</div>
              </div>
            </div>
            <div className="delivery-row">
              <span>🛒</span>
              <div>
                <div className="delivery-label">Items ordered</div>
                <div className="delivery-value">{orderSummary.itemCount} ingredients</div>
              </div>
            </div>
            <div className="delivery-row">
              <span>💳</span>
              <div>
                <div className="delivery-label">Total charged</div>
                <div className="delivery-value">£{orderSummary.total}</div>
              </div>
            </div>
          </div>
          <p style={{ fontSize: 13, color: '#6B7280', marginBottom: 20 }}>
            Confirmation sent to your email.
          </p>
          <button className="main-btn" onClick={handleRestart}>
            Start a new order
          </button>
        </div>
      )}
    </div>
  );
}

export default App;
